@rendermode InteractiveServer
@using sv_5022afca3f04480c9a5bb4fad172d996.Services
@inject AppointmentService AppointmentService

<h1>Book an Appointment</h1>

@* Step 1: Patient Information *@
<EditForm EditContext="step1Context" OnValidSubmit="HandleStep1Submit" FormName="step1">
    <DataAnnotationsValidator />
    <CustomValidator @ref="step1CustomValidator" />

    <h2>Step 1: Patient Information</h2>

    <div class="mb-3">
        <label class="form-label">Patient Name</label>
        <InputText class="form-control" @bind-Value="step1Model.PatientName" />
        <ValidationMessage For="() => step1Model.PatientName" />
    </div>

    <div class="mb-3">
        <label class="form-label">Email</label>
        <InputText class="form-control" @bind-Value="step1Model.Email" />
        <ValidationMessage For="() => step1Model.Email" />
    </div>

    <div class="mb-3">
        <label class="form-label">Phone</label>
        <InputText class="form-control" @bind-Value="step1Model.Phone" />
        <ValidationMessage For="() => step1Model.Phone" />
    </div>

    <div class="mb-3">
        <label class="form-label">Insurance Provider</label>
        <InputSelect class="form-select" @bind-Value="step1Model.InsuranceProvider">
            <option value="">-- Select --</option>
            <option value="Aetna">Aetna</option>
            <option value="BlueCross">BlueCross</option>
            <option value="Cigna">Cigna</option>
            <option value="UnitedHealth">UnitedHealth</option>
            <option value="None">None</option>
        </InputSelect>
        <ValidationMessage For="() => step1Model.InsuranceProvider" />
    </div>

    @if (!showStep2)
    {
        <button type="submit" class="btn btn-primary">Next</button>
    }
</EditForm>

@* Step 2: Appointment Details *@
@if (showStep2)
{
    <EditForm EditContext="step2Context" OnValidSubmit="HandleStep2Submit" FormName="step2">
        <DataAnnotationsValidator />
        <CustomValidator @ref="step2CustomValidator" />

        <h2>Step 2: Appointment Details</h2>

        <div class="mb-3">
            <label class="form-label">Preferred Doctor</label>
            <InputSelect class="form-select" @bind-Value="appointmentModel.Doctor">
                <option value="">-- Select --</option>
                @foreach (var doctor in doctors)
                {
                    <option value="@doctor">@doctor</option>
                }
            </InputSelect>
            <ValidationMessage For="() => appointmentModel.Doctor" />
        </div>

        <div class="mb-3">
            <label class="form-label">Date</label>
            <InputDate class="form-control" @bind-Value="appointmentModel.AppointmentDate" @bind:after="OnDateChanged" />
            <ValidationMessage For="() => appointmentModel.AppointmentDate" />
            @if (appointmentModel.AppointmentDate.HasValue && appointmentModel.AppointmentDate.Value <= DateOnly.FromDateTime(DateTime.Today))
            {
                <div class="text-danger">Date must be in the future.</div>
            }
        </div>

        <div class="mb-3">
            <label class="form-label">Time Slot</label>
            <InputSelect class="form-select" @bind-Value="appointmentModel.TimeSlot">
                <option value="">-- Select --</option>
                @foreach (var slot in availableSlots)
                {
                    <option value="@slot">@slot</option>
                }
            </InputSelect>
            <ValidationMessage For="() => appointmentModel.TimeSlot" />
        </div>

        <div class="mb-3">
            <label class="form-label">Reason for Visit</label>
            <InputTextArea class="form-control" @bind-Value="appointmentModel.Reason" rows="4" />
            <ValidationMessage For="() => appointmentModel.Reason" />
        </div>

        <button type="submit" class="btn btn-success" disabled="@isSubmitting">
            @(isSubmitting ? "Checking..." : "Check Availability")
        </button>

        @if (bookingConfirmed)
        {
            <div class="alert alert-success mt-3">Appointment booked successfully!</div>
        }
    </EditForm>
}

@code {
    private AppointmentStep1Model step1Model = new();
    private AppointmentModel appointmentModel = new();

    private EditContext? step1Context;
    private EditContext? step2Context;

    private CustomValidator? step1CustomValidator;
    private CustomValidator? step2CustomValidator;

    private bool showStep2;
    private bool isSubmitting;
    private bool bookingConfirmed;

    private List<string> doctors = new();
    private List<string> availableSlots = new();

    protected override async Task OnInitializedAsync()
    {
        step1Context = new EditContext(step1Model);
        step2Context = new EditContext(appointmentModel);
        doctors = await AppointmentService.GetDoctorsAsync();
    }

    private void HandleStep1Submit()
    {
        showStep2 = true;
        // Copy step 1 data into the full model
        appointmentModel.PatientName = step1Model.PatientName;
        appointmentModel.Email = step1Model.Email;
        appointmentModel.Phone = step1Model.Phone;
        appointmentModel.InsuranceProvider = step1Model.InsuranceProvider;
    }

    private async Task OnDateChanged()
    {
        if (appointmentModel.AppointmentDate.HasValue && !string.IsNullOrEmpty(appointmentModel.Doctor))
        {
            availableSlots = await AppointmentService.GetAvailableTimeSlotsAsync(
                appointmentModel.Doctor, appointmentModel.AppointmentDate.Value);
        }
    }

    private async Task HandleStep2Submit()
    {
        // Validate future date
        if (appointmentModel.AppointmentDate.HasValue
            && appointmentModel.AppointmentDate.Value <= DateOnly.FromDateTime(DateTime.Today))
        {
            step2CustomValidator!.DisplayErrors(new Dictionary<string, List<string>>
            {
                [nameof(AppointmentModel.AppointmentDate)] = new() { "Date must be in the future." }
            });
            return;
        }

        isSubmitting = true;
        bookingConfirmed = false;

        try
        {
            // Sync step 1 fields in case they were edited
            appointmentModel.PatientName = step1Model.PatientName;
            appointmentModel.Email = step1Model.Email;
            appointmentModel.Phone = step1Model.Phone;
            appointmentModel.InsuranceProvider = step1Model.InsuranceProvider;

            var errors = await AppointmentService.ValidatePatientAsync(
                appointmentModel.Email!,
                appointmentModel.InsuranceProvider!,
                appointmentModel.Doctor!,
                appointmentModel.TimeSlot!);

            if (errors.Count > 0)
            {
                // Map errors to the correct form contexts
                var step1Errors = new Dictionary<string, List<string>>();
                var step2Errors = new Dictionary<string, List<string>>();

                foreach (var (field, messages) in errors)
                {
                    if (field is nameof(AppointmentModel.Email))
                        step1Errors[field] = messages;
                    else
                        step2Errors[field] = messages;
                }

                if (step1Errors.Count > 0)
                    step1CustomValidator!.DisplayErrors(step1Errors);
                if (step2Errors.Count > 0)
                    step2CustomValidator!.DisplayErrors(step2Errors);

                return;
            }

            bookingConfirmed = true;
        }
        finally
        {
            isSubmitting = false;
        }
    }
}
"}

{"path": "/tmp/sv-5022afca3f04480c9a5bb4fad172d996/Components/CustomValidator.razor", "file_text": "@using Microsoft.AspNetCore.Components.Forms

@code {
    [CascadingParameter]
    private EditContext? EditContext { get; set; }

    private ValidationMessageStore? messageStore;

    protected override void OnInitialized()
    {
        messageStore = new ValidationMessageStore(EditContext!);
        EditContext!.OnValidationRequested += (s, e) => messageStore.Clear();
        EditContext!.OnFieldChanged += (s, e) => messageStore.Clear(e.FieldIdentifier);
    }

    public void DisplayErrors(Dictionary<string, List<string>> errors)
    {
        foreach (var (field, messages) in errors)
        {
            foreach (var message in messages)
            {
                messageStore!.Add(EditContext!.Field(field), message);
            }
        }
        EditContext!.NotifyValidationStateChanged();
    }

    public void ClearErrors()
    {
        messageStore?.Clear();
        EditContext?.NotifyValidationStateChanged();
    }
}
"}

